# scorers/exact_match.py
from scorer_protocol import Scorer, ScoreResult

class ExactMatchScorer:
    name      = "exact-match"
    version   = "1.0.0"
    threshold = 1.0

    def score(self, input, output, expected, context, metadata) -> ScoreResult:
        if expected is None:
            raise ValueError("exact-match requires expected_output")
        passed = output.strip().lower() == expected.strip().lower()
        return ScoreResult(score=float(passed), passed=passed, details={})

def compare_to_baseline(
    current: dict[str, float],
    baseline_run_id: str,
    threshold: float,
) -> dict:
    baseline = eval_store.get_scores(baseline_run_id)
    regressions = {}
    for scorer, score in current.items():
        delta = score - baseline.get(scorer, score)
        if delta < -threshold:
            regressions[scorer] = {
                "baseline": baseline[scorer],
                "current":  score,
                "delta":    delta,
                "regressed": True,
            }
    return {
        "has_regression": bool(regressions),
        "details":        regressions,
        "threshold":      threshold,
    }
